-- Function to auto-update updated_at timestamp
CREATE OR REPLACE FUNCTION touch_updated_at () RETURNS trigger AS $$
BEGIN
  IF (to_jsonb(NEW) - 'updated_at') IS DISTINCT FROM (to_jsonb(OLD) - 'updated_at') THEN
    NEW.updated_at := now();
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

