-- InsertInitialData
UPDATE "locale"
SET
  "region" = 'US',
  "name" = 'English (United States)'
WHERE
  "code" = 'en';

INSERT INTO
  "locale" ("code", "region", "name")
SELECT
  'en',
  'US',
  'English (United States)'
WHERE
  NOT EXISTS (
    SELECT
      1
    FROM
      "locale"
    WHERE
      "code" = 'en'
  );

UPDATE "locale"
SET
  "region" = 'BR',
  "name" = 'Português (Brasil)'
WHERE
  "code" = 'pt';

INSERT INTO
  "locale" ("code", "region", "name")
SELECT
  'pt',
  'BR',
  'Português (Brasil)'
WHERE
  NOT EXISTS (
    SELECT
      1
    FROM
      "locale"
    WHERE
      "code" = 'pt'
  );

UPDATE "locale"
SET
  "region" = 'ES',
  "name" = 'Español (España)',
  "enabled" = FALSE
WHERE
  "code" = 'es';

INSERT INTO
  "locale" ("code", "region", "name", "enabled")
SELECT
  'es',
  'ES',
  'Español (España)',
  FALSE
WHERE
  NOT EXISTS (
    SELECT
      1
    FROM
      "locale"
    WHERE
      "code" = 'es'
  );

