UPDATE "mail_locale"
SET
  "subject" = 'New login from a new device',
  "body" = 'Hello {{name}},<br>
We noticed a login to your HedHog account from a new device.<br>
Here are the details of the login:<br>
• User Agent: {{userAgent}}<br>
• IP Address: {{ipAddress}}<br>
• Location: {{location}}<br>
If this was you, no further action is needed. 
If you did not recognize this activity, 
please secure your account immediately.<br>
Best regards,<br>
The HedHog Team
'
WHERE
  "locale_id" = (
    SELECT
      "id"
    FROM
      "locale"
    WHERE
      "code" = 'en'
  )
  AND "mail_id" = (
    SELECT
      "id"
    FROM
      "mail"
    WHERE
      "slug" = 'auth-login-new-device'
  );

